{
  "classification": "NOVELTY_ONLY_REPAIRABLE",
  "boundary_action": "ONE_BOUNDED_NON_IDENTICAL_RETRY",
  "extra_revisions": [
    "Correct every attribution of Lanners et al.'s population results from Section 4, Lemma 1 and Theorem 1 to Section 4, Lemma 4 and Theorem 4.",
    "Add Yu, Karmakar, Vandeleest, and Schwarz, arXiv:2412.03731, throughout the literature-facing fields."
  ],
  "root_cause": "The verified rerun found no structural or soundness defect: S=0, C=0, and the FIELD tier remains intact. The remaining defects are bounded literature-curation errors—one incorrect result-number anchor and one omitted materially close comparator. A retry is justified because it is low-cost, fully specified, and non-identical: it corrects source localization and materially expands the comparison set rather than repeating the prior review. Switching or giving up would be disproportionate.",
  "directive": {
    "atomic_instruction": "Perform one literature-only revision pass and then rerun the reviewer once. Do not alter the mathematical model, estimand, assumptions, definitions, statements, witness, inference construction, claimed tier, or open/proved statuses.",
    "lanners_anchor_repairs": [
      "In related_work, replace the Lanners attribution 'Section 4, Lemma 1, Theorem 1, and Remark 1' with 'Section 4, Lemma 4, Theorem 4, and Remark 1'.",
      "In comparator_promise_table, replace 'Section 4, Lemma 1, Theorem 1, and Remark 1 impose pointwise population interval inequalities' with 'Section 4, Lemma 4, Theorem 4, and Remark 1 impose pointwise population interval inequalities'.",
      "Apply the same Lemma 1→Lemma 4 and Theorem 1→Theorem 4 correction to every literature checklist, introduction, result annotation, or generated prose location that attributes those numbered results to Lanners et al. Do not change internal references such as 'Lemma 1' or 'Proposition 1' when they refer to this proposal's own statements."
    ],
    "bibliography_addition": {
      "key": "YuKarmakarVandeleestSchwarz2024",
      "citation": "M. Yu, B. Karmakar, J. Vandeleest, and E. B. Schwarz. “Using a Two-Parameter Sensitivity Analysis Framework to Efficiently Combine Randomized and Non-randomized Studies.” arXiv:2412.03731, 2024."
    },
    "related_work_addition": "Yu, Karmakar, Vandeleest, and Schwarz develop a materially close two-parameter framework for combining randomized and non-randomized studies, using triplet matching and separate sensitivity parameters for internal and external bias. Their framework studies sensitivity of an integrated matched analysis under those bias parameters; it does not provide the present observed-law, support-clipped zero-violation characterization of whether both restrictions admit one common latent causal extension, nor the proposed tie-inclusive inference for the full compatibility region.",
    "project_positioning_addition": "State in the project justification and concise project summary that two-parameter RCT/observational fusion sensitivity analysis already exists in Yu et al. The proposed advance is therefore not the existence of two sensitivity parameters or joint use of randomized and observational data. The narrower proposed contribution is an exact common-extension compatibility question for the corrected published Lanners sensitivity model, a no-cancellation observed-law functional and witness, and inference for its compatibility zero set.",
    "literature_checklist_addition": "Add YuKarmakarVandeleestSchwarz2024 as a checked close comparator. Record: randomized plus non-randomized study fusion; triplet matching; two parameters representing internal and external bias; materially close in topic and parameterization; does not establish the support-clipped common-latent-extension iff, the no-cancellation functional C_P, the stated cancellation witness, or the tie-inclusive learned-nuisance zero-set inference result.",
    "comparator_table_addition": {
      "comparator_bibkey": "YuKarmakarVandeleestSchwarz2024",
      "comparator_claim": "Uses triplet matching and two sensitivity parameters for internal and external bias to combine randomized and non-randomized studies, but does not characterize the observed-law support-clipped region admitting one common latent causal extension.",
      "matched_by": "Open-ended Question 1",
      "match_kind": "downgraded_to_informed_by"
    },
    "non_overclaiming_rule": "Do not claim that Yu et al. lacks a two-parameter compatibility or sensitivity analysis in a generic sense. Distinguish methods and targets precisely: Yu et al. supplies a two-parameter matched sensitivity analysis for internal and external bias, whereas this proposal asks whether the particular Lanners interval restrictions are jointly realizable by one support-respecting latent law and studies the zero set of a no-cancellation observed-law functional."
  },
  "faithfulness_check": {
    "published_sensitivity_model": "Preserve the corrected linear relative-unmeasured-confounding and study-exchangeability restrictions, including support clipping in C_t, V_t, and W_t.",
    "witness": "Preserve the recomputed two-stratum witness exactly, including G_0^{LRVP}=0, G_1^{LRVP}=1, the sole arm-zero conditional violation 9/8 at x_1, and C_{P^{can}}(1,1)=9/10.",
    "floor": "FIELD",
    "question_status": {
      "oeq:exact-compatibility": "open; sufficiency remains to prove",
      "oeq:uniform-contact-inference": "open; uniform coverage, testing, separation, and local power remain to prove"
    },
    "scope_guard": "Make no mathematical strengthening, downgrade, or closure claim during this retry."
  }
}

{
  "classification": "accept",
  "accepted_selectors": [
    "statement-replace:prop:positive-violation-infeasibility",
    "statement-replace:prop:two-stratum-cancellation",
    "rebuild-reverse-dependencies:metadata:reverse-dependencies"
  ],
  "rejected_selectors": [],
  "required_note": "Authorize only the three listed selectors. The two statement replacements preserve their live claim text exactly and may pair only with their same-round proofs; the reverse-dependency rebuild is independent. The other four provisional proofs authorize no mutation. The paper TLDR, project-justification prose, and honest-scope prose remain stale about exact compatibility, while oeq:uniform-contact-inference is marked resolved despite its replacement theorem explicitly leaving coverage and uniform-level validity undecided. Correcting those defects requires separately proposed edits and is not authorized here.",
  "mathematical_findings": [
    {
      "id": "statement-replace:prop:positive-violation-infeasibility",
      "finding": "accept",
      "detail": "The replacement is a dependency-only correction: the statement exactly echoes the live claim, and uniform study positivity is genuinely required to divide the weighted mixture identity by 1-pi(X). The remaining dependencies faithfully cover the latent class, relative-NUC and study-exchangeability restrictions, exact endpoints, and compatibility functional. No assumption is laundered."
    },
    {
      "id": "statement-replace:prop:two-stratum-cancellation",
      "finding": "accept",
      "detail": "The replacement exactly echoes the live claim and adds the missing direct dependency on def:endpoint-kernel. The displayed probabilities, published intervals, signed cancellation, clipped intervals, 9/8 conditional violation, and 9/10 functional value are correct. Kernel validity specifically uses nu_m, so the added edge is faithful."
    },
    {
      "id": "rebuild-reverse-dependencies:metadata:reverse-dependencies",
      "finding": "accept",
      "detail": "An independent rebuild is appropriate after adding the uniform-study-positivity and endpoint-kernel edges. It authorizes metadata reconstruction only and does not authorize any statement, definition, assumption, proof, OEQ, or prose mutation."
    },
    {
      "id": "oeq:exact-compatibility",
      "finding": "intentionally_and_validly_resolved",
      "detail": "The durable source fingerprint and theorem mapping show intentional resolution by thm:exact-compatibility-characterization. Its necessity and measurable common-extension construction are valid under the stated standard-Borel and positivity assumptions: observed conditional kernels are disintegrated, trial potential outcomes are coupled independently with an assignment-invariant joint kernel, and observational missing potentials use measurable endpoint kernels with the selected means."
    },
    {
      "id": "oeq:uniform-contact-inference",
      "finding": "intentionally_but_incompletely_resolved",
      "detail": "The durable source fingerprint and theorem mapping show intentional replacement by thm:tie-local-separation-obstruction. The replacement validly answers the local-power component negatively and establishes a slower tie-subexperiment minimax boundary, but it explicitly neither proves nor refutes uniform coverage or uniform level for the proposed numerical directional-delta procedure. Therefore the original multipart OEQ is not substantively discharged in full."
    }
  ],
  "proof_findings": [
    {
      "id": "lem:observational-mixture-identity",
      "finding": "valid",
      "detail": "Conditional iterated expectation, pushforward, consistency through Y(A), and weighting by observational-study mass prove the stated weighted identity without positivity. Division is correctly restricted to pi<1."
    },
    {
      "id": "prop:positive-violation-infeasibility",
      "finding": "valid_and_exact_echo",
      "detail": "Uniform study positivity justifies division; treatment positivity supplies common arm-specific support; relative NUC maps q_t0 into W_t; study exchangeability maps it into V_t; hence every positive-part violation vanishes and C_P(theta)=0, contradicting the premise."
    },
    {
      "id": "prop:two-stratum-cancellation",
      "finding": "valid_and_exact_echo",
      "detail": "The endpoint-kernel validity check and every interval, signed-average, clipped-gap, expectation, positivity, and infeasibility calculation are correct."
    },
    {
      "id": "lem:zero-sensitivity-reduction",
      "finding": "valid",
      "detail": "At zero sensitivity the clipped C and V intervals collapse to the corresponding observed means, W collapses to mu_0t, and the functional becomes the maximum armwise expected absolute study-mean difference."
    },
    {
      "id": "lem:tie-subexperiment-minimax-boundary",
      "finding": "valid_with_declared_subexperiment_scope",
      "detail": "The target reduction, Rademacher-bump chi-square mixture bound, rate n^{-2beta/(4beta+d)}, root-n indistinguishability construction, projection-statistic expectation, approximation bound, and variance argument are coherent. The result is conditional on choosing the fixed model constants B and density bounds to contain the displayed subexperiment and does not establish validity of the proposed numerical directional-delta procedure."
    },
    {
      "id": "lem:regular-constant-path-power",
      "finding": "valid",
      "detail": "The mean, second moment, limiting variance, triangular-array CLT, shifted-normal limit, and two-sided local-power formula are correct, including for negative kappa."
    }
  ],
  "faithfulness_check": {
    "result": "structured_edits_faithful_but_current_prose_not_fully_consistent",
    "detail": "The mathematics preserves the published-model distinction between un-clipped pointwise intervals and their signed-average operational proxy, while the proposed exact functional uses support clipping and nonnegative conditional violations. The two statement replacements are exact claim echoes. However, the current paper still says the exact-extension conjecture remains open after presenting a proved characterization, and it describes all inference components as open after proving the local-separation obstruction. Those are unproposed prose defects."
  },
  "next_action": "At D0.5, apply only the three accepted selectors, pairing only the two corresponding same-round proofs, then stop. Do not launch any F stage. Treat D0.5 as blocked from a fully faithful completion until separately proposed edits repair the stale exact-compatibility prose and restore or narrow the unresolved coverage-and-level portion of oeq:uniform-contact-inference."
}

